sys_ws_operation.operation_script:
(function process( /*RESTAPIRequest*/ request, /*RESTAPIResponse*/ response) {

    // implement resource here
    var requestBody = request.body;
    var requestString = requestBody.dataString;
    var requestObj = JSON.parse(requestString);

    /* {
    "Name": "test",
    "Id": "12345678",
    "Genre": "Drama",
    "Overview": "test movie",
    "Rating": "8.0",
    "ReleaseDate": "2026-04-19"
} */

    try {
        var mandatoryParameter = [];
        if (!requestObj.id) {
            mandatoryParameter.push("Id");
        }
        if (mandatoryParameter.length > 0) {
            response.setError(new sn_ws_err.BadRequestError("Mandatory parameters are/is missing: " + mandatoryParameter.join(", ")));
			return;
        }

        var grWatchList = new GlideRecord('x_1962882_show_s_0_my_watchlist');
        grWatchList.initialize();
        grWatchList.name = requestObj.Name;
        grWatchList.id = requestObj.Id;
        grWatchList.genres = requestObj.Genre;
        grWatchList.overview = requestObj.Overview;
        grWatchList.rating = requestObj.Rating;
        grWatchList.release_date = requestObj.ReleaseDate;
        grWatchList.insert();
        var responseObj = {
            "Record": grWatchList.sys_id.toString(),
            "Message": "Successfully added to watchlist"
        };
        response.setBody(responseObj);
        response.setStatus(201);

    } catch (ex) {
        var serviceError = new sn_ws_err.ServiceError();
        serviceError.setStatus(500);
        serviceError.setMessage("Service error");
        serviceError.setDetail("The server could not process the request");
        response.setError(serviceError);
    }

})(request, response);
